import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { FaEye, FaEyeSlash, FaSpinner, FaUser, FaUserMd, FaPills } from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // 'role' | 'credentials'
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const roles = [
    // Order: Patient first, then Doctor, then Pharmacist
    {
      id: 'patient',
      icon: FaUser,
      name: t('patient') || 'Patient',
      gradient: 'from-rose-500 to-orange-400',
      usernamePrefix: 'p',
      sampleUsername: 'p001'
    },
    {
      id: 'doctor',
      icon: FaUserMd,
      name: t('doctor') || 'Doctor',
      gradient: 'from-sky-500 to-cyan-500',
      usernamePrefix: 'd',
      sampleUsername: 'd001'
    },
    {
      id: 'pharmacist',
      icon: FaPills,
      name: t('pharmacist') || 'Pharmacist',
      gradient: 'from-emerald-500 to-pink-400',
      usernamePrefix: 'pm',
      sampleUsername: 'pm001'
    }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      console.log('🔐 Attempting login with:', { username, role: selectedRole });
      
      // Username-only auth (no email supported)
      const payload = {
        username: username,
        password: password
      };
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload)
      });
      
      console.log('📡 Response status:', response.status);
      
  let data = {};
      try {
        data = await response.json();
      } catch (e) {
        console.error('Failed to parse JSON response');
      }
      console.log('� Response data:', data);
      
      if (response.ok) {
        // Accept either 'token' or 'access_token' from backend
        const token = data.token || data.access_token;
        const user = data.user || {
          id: data.id || data.user_id,
          role: data.role || data.user_type,
          username: data.username || username,
        };
        
        if (!token) {
          throw new Error('Missing token in response');
        }
        
        // Store token and user in localStorage
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        
        console.log('✅ Login successful, redirecting...');
        
        // Call onLogin with user data
        onLogin({
          ...user,
          token
        });
      } else {
        console.error('❌ Login failed:', data);
        // Normalize error message
        const serverMsg = data?.message || data?.error || 'Login failed';
        setError(serverMsg);
      }
    } catch (err) {
      console.error('🚨 Login error:', err);
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        setError('Unable to connect to server. Please ensure the backend is running on http://localhost:5000');
      } else {
        setError('Network error. Please check your connection and try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch (role) {
      case 'patient':
        return 'patient123';
      case 'doctor':
        return 'doctor123';
      case 'pharmacist':
        return 'pharmacy123';
      default:
        return '';
    }
  };

  const fillSampleCredentials = () => {
    const role = getCurrentRole();
    if (role) {
      setUsername(role.sampleUsername);
      setPassword(getPasswordForRole(selectedRole));
    }
  };
  return (
    <div className="login-shell">
      <div className="login-card">
        {/* Hero */}
        <header className="text-center mb-6">
          <h1 className="hero-title">
            Helio Healthcare Platform
          </h1>
          <p className="hero-subtitle">Choose Your Role</p>
        </header>

        {/* Card wrapper for content */}
        <div>
          {/* Step 1: Role selection */}
          {step === 'role' && (
            <div>
              <div className="role-list" style={{display: 'flex', flexDirection: 'column', gap: '0.75rem'}}>
                {roles.map((role) => {
                  const Icon = role.icon;
                  // Inline mapping to ensure Tailwind picks up gradient classes
                  const variant = role.id === 'patient' ? 'role-patient' : role.id === 'doctor' ? 'role-doctor' : 'role-pharmacist';
                  return (
                    <button
                      key={role.id}
                      onClick={() => handleRoleSelect(role.id)}
                      className={`role-btn ${variant}`}
                      aria-label={`Select ${role.name}`}
                    >
                      <div className="flex items-center justify-between">
                        <div className="left">
                          <div className="icon-badge">
                            <Icon />
                          </div>
                          <span className="role-label">{role.name}</span>
                        </div>
                        {/* Chevron removed as requested */}
                      </div>
                    </button>
                  );
                })}
              </div>

              {/* Demo Credentials Card */}
              <div className="card demo-card" style={{marginTop: '1rem'}}>
                <h3>Demo Credentials</h3>
                <div style={{display: 'flex', flexDirection: 'column', gap: '.75rem'}}>
                  <div className="demo-row">
                    <div className="demo-left">
                      <span className="inline-flex w-8 h-8 rounded-lg bg-purple-100 text-purple-600 items-center justify-center"><FaUser /></span>
                      Patient
                    </div>
                    <div className="demo-right">p001 / patient123</div>
                  </div>
                  <div className="demo-row">
                    <div className="demo-left">
                      <span className="inline-flex w-8 h-8 rounded-lg bg-sky-100 text-sky-600 items-center justify-center"><FaUserMd /></span>
                      Doctor
                    </div>
                    <div className="demo-right">d001 / doctor123</div>
                  </div>
                  <div className="demo-row">
                    <div className="demo-left">
                      <span className="inline-flex w-8 h-8 rounded-lg bg-rose-100 text-rose-600 items-center justify-center"><FaPills /></span>
                      Pharmacist
                    </div>
                    <div className="demo-right">pm001 / pharmacy123</div>
                  </div>
                </div>
              </div>

              {/* Removed Default Passwords Card as requested */}
            </div>
          )}

          {/* Step 2: Credentials */}
          {step === 'credentials' && (
            <div className="space-y-5">
              <div className="text-center">
                <p className="text-sm text-gray-500 mb-1">Role</p>
                <h2 className="text-2xl font-extrabold text-gray-900">{getCurrentRole()?.name} Portal</h2>
              </div>

              {error && (
                <div className="p-3 rounded-lg bg-red-50 border border-red-200 text-red-800 text-sm">
                  {error}
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-600 mb-1">Username</label>
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                    className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-sky-200 focus:border-sky-400 text-base"
                    disabled={isLoading}
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-600 mb-1">Password</label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter your password"
                      className="w-full px-4 py-3 pr-12 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-sky-200 focus:border-sky-400 text-base"
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
                    >
                      {showPassword ? <FaEyeSlash /> : <FaEye />}
                    </button>
                  </div>
                </div>

                <div className="rounded-lg border border-dashed border-gray-300 p-3 flex items-center justify-between bg-gray-50">
                  <div>
                    <p className="text-sm font-semibold text-gray-700">Quick Demo Access</p>
                    <p className="text-xs text-gray-500">Auto-fill sample credentials</p>
                  </div>
                  <button
                    onClick={fillSampleCredentials}
                    className="px-3 py-2 rounded-md bg-gray-900 text-white text-sm font-bold disabled:opacity-50"
                    disabled={isLoading}
                  >
                    Fill ({getCurrentRole()?.sampleUsername})
                  </button>
                </div>

                <div className="flex gap-3 pt-2">
                  <button
                    onClick={handleBack}
                    className="flex-1 py-3 rounded-lg border border-gray-300 text-gray-800 font-bold"
                    disabled={isLoading}
                  >
                    Back
                  </button>
                  <button
                    onClick={handleLogin}
                    disabled={isLoading || !username || !password}
                    className="flex-1 py-3 rounded-lg text-white font-bold bg-gray-900 disabled:opacity-50 flex items-center justify-center gap-2"
                  >
                    {isLoading && <FaSpinner className="animate-spin" />}
                    {isLoading ? 'Authenticating…' : 'Secure Login'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
